#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int value;
    struct Node* next;
} Node;

typedef struct PersistentList {
    Node** versions;
    int version_count;
} PersistentList;

Node* createNode(int value, Node* next) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->value = value;
    node->next = next;
    return node;
}

PersistentList* createPersistentList() {
    PersistentList* plist = (PersistentList*)malloc(sizeof(PersistentList));
    plist->versions = NULL;
    plist->version_count = 0;
    return plist;
}

void insert(PersistentList* plist, int value) {
    plist->versions = (Node**)realloc(plist->versions, (plist->version_count + 1) * sizeof(Node*));
    if (plist->version_count == 0) {
        plist->versions[0] = createNode(value, NULL);
    } else {
        plist->versions[plist->version_count] = createNode(value, plist->versions[plist->version_count - 1]);
    }
    plist->version_count++;
}

int search(PersistentList* plist, int version, int value) {
    Node* node = version < plist->version_count ? plist->versions[version] : NULL;
    while (node) {
        if (node->value == value) return 1;
        node = node->next;
    }
    return 0;
}

void freePersistentList(PersistentList* plist) {
    for (int i = 0; i < plist->version_count; i++) {
        Node* node = plist->versions[i];
        while (node) {
            Node* temp = node;
            node = node->next;
            if (i == plist->version_count - 1) free(temp);
        }
    }
    free(plist->versions);
    free(plist);
}

int main() {
    PersistentList* plist = createPersistentList();
    int values[] = {10, 20, 30, 40};
    for (int i = 0; i < 4; i++) {
        insert(plist, values[i]);
    }
    printf("Search version 2 for 30: %d\n", search(plist, 2, 30));
    printf("Search version 2 for 50: %d\n", search(plist, 2, 50));
    freePersistentList(plist);
    return 0;
}
// Output: Search version 2 for 30: 1
// Output: Search version 2 for 50: 0

