#include <iostream>
#include <vector>

class Node {
public:
    int value;
    Node* next;

    Node(int value, Node* next = nullptr) : value(value), next(next) {}
};

class PersistentList {
private:
    std::vector<Node*> versions;

public:
    PersistentList() {}

    void insert(int value) {
        if (versions.empty()) {
            versions.push_back(new Node(value));
        } else {
            versions.push_back(new Node(value, versions.back()));
        }
    }

    bool search(int version, int value) {
        Node* node = version < versions.size() ? versions[version] : nullptr;
        while (node) {
            if (node->value == value) return true;
            node = node->next;
        }
        return false;
    }

    ~PersistentList() {
        for (size_t i = 0; i < versions.size(); i++) {
            Node* node = versions[i];
            while (node && i == versions.size() - 1) {
                Node* temp = node;
                node = node->next;
                delete temp;
            }
        }
    }
};

int main() {
    PersistentList plist;
    int values[] = {10, 20, 30, 40};
    for (int value : values) {
        plist.insert(value);
    }
    std::cout << "Search version 2 for 30: " << (plist.search(2, 30) ? "true" : "false") << "\n";
    std::cout << "Search version 2 for 50: " << (plist.search(2, 50) ? "true" : "false") << "\n";
    return 0;
}
